import React, { useCallback, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  DateRangeFilter,
  SearchTextInput,
  dispatchAppToast,
  LinPageLayout,
  LinListTableConfigModal,
  loadErpListTableConfig,
  saveErpListTableConfig,
  useViewMobileLayout,
  useErpListSelection,
  type DateRangeValue,
  type ErpListTableConfig,
} from '@linm-soft/common-components';
import { VoucherStatusBadge } from '../voucher/VoucherStatusBadge';
import { useAppDispatch } from '../../store/hooks';
import { bhService } from '../../services/bh/bhService';
import type { OrderDto } from '../../services/bh/models';
import { formatDateLocal, formatVnd } from '../../utils/format';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import {
  VOUCHER_LIST_ROW_MENU_HINT_DESKTOP,
  VOUCHER_LIST_ROW_MENU_HINT_TOUCH,
  voucherListRowMenuHintDismissStorageKey,
} from '../../utils/voucherListRowMenuHint';
import { canEditOrderFromListRow } from '../../utils/orderListRowActions';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import { useVoucherListActions } from '../../hooks/useVoucherListActions';
import { LIST_FILTER_SCOPE } from '../../constants/listFilterScopes';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../voucher-list/VoucherRowActionMenu';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../list/VoucherListPagination';
import { useVoucherListTableBusy } from '../list/useVoucherListTableBusy';
import erp from '../../styles/erpPage.module.css';

const TEST_ID = 'bh-don-hang';
const PAGE_ID = 'bh-don-hang';
const CREATE_FORM = 'create-sales-order';

const STATUS_OPTIONS = [
  { value: '', label: 'Tất cả' },
  { value: 'Draft', label: 'Nháp' },
  { value: 'Confirmed', label: 'Đã xác nhận' },
  { value: 'Cancelled', label: 'Đã hủy' },
];

const LIST_COLUMNS = [
  { id: 'code', label: 'Số ĐH' },
  { id: 'orderDate', label: 'Ngày' },
  { id: 'customerName', label: 'Khách hàng' },
  { id: 'totalAmount', label: 'Tổng tiền' },
  { id: 'status', label: 'Trạng thái' },
] as const;

function filterBySearch(rows: OrderDto[], search: string): OrderDto[] {
  const q = search.trim().toLowerCase();
  if (!q) return rows;
  return rows.filter(
    r =>
      r.code.toLowerCase().includes(q) ||
      (r.customerName ?? '').toLowerCase().includes(q) ||
      (r.description ?? '').toLowerCase().includes(q),
  );
}

export const DonHangList: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const viewMobile = useViewMobileLayout();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(LIST_FILTER_SCOPE.donHang);
  const [items, setItems] = useState<OrderDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<ListPageSize>(DEFAULT_PAGE_SIZE);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(TEST_ID),
  );
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: OrderDto } | null>(null);
  const [confirming, setConfirming] = useState(false);

  const { canCreate, canUpdate, canApprove } = useVoucherListActions(CREATE_FORM);
  const { showTableLoading, pulseSearch } = useVoucherListTableBusy(loading);

  const visibleColumns = LIST_COLUMNS;

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: r => r.status === 'Draft',
  });

  const activeRow = selection.activeRow;
  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow
    ? canEditOrderFromListRow(activeRow.status, canUpdate)
    : false;
  const canConfirmActive = Boolean(activeRow?.status === 'Draft' && canApprove);

  const refresh = useCallback(() => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection]);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setPage(1);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    });
  };

  const setPageSize = (size: number) => {
    setPageSizeState(size as ListPageSize);
    setPage(1);
    selection.clearSelection();
  };

  const navigateToRow = useCallback(
    (id: string, startInEditMode?: boolean) => {
      navigate(`/bh/dh/${id}`, {
        state: startInEditMode ? { startInEditMode: true } : undefined,
      });
    },
    [navigate],
  );

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      bhService
        .getOrders({
          fromDate,
          toDate,
          status: status || undefined,
          page,
          pageSize,
        })
        .then(res => {
          if (cancelled) return;
          const filtered = filterBySearch(res.items, search);
          setItems(filtered);
          setTotalCount(search.trim() ? filtered.length : res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, 'Lỗi tải danh sách đơn hàng'),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [initialized, fromDate, toDate, status, page, pageSize, search, reloadKey, dispatch]);

  const handleConfirmActive = async () => {
    if (!activeRow || activeRow.status !== 'Draft') return;
    setConfirming(true);
    try {
      await bhService.confirmOrder(activeRow.id);
      dispatchAppToast(dispatch, { message: 'Xác nhận đơn hàng thành công', type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Xác nhận thất bại'),
        type: 'error',
      });
    } finally {
      setConfirming(false);
    }
  };

  const handleSaveTableConfig = (config: ErpListTableConfig) => {
    setTableConfig(config);
    saveErpListTableConfig(TEST_ID, config);
    setShowConfigModal(false);
  };

  const rowMenuHintMessage = viewMobile
    ? VOUCHER_LIST_ROW_MENU_HINT_TOUCH
    : VOUCHER_LIST_ROW_MENU_HINT_DESKTOP;

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: OrderDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      if (action === 'view') navigateToRow(row.id);
      if (action === 'edit' && canEditOrderFromListRow(row.status, canUpdate)) {
        navigateToRow(row.id, true);
      }
    },
    [rowMenu?.row, canUpdate, navigateToRow],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = rowMenuRow
    ? canEditOrderFromListRow(rowMenuRow.status, canUpdate)
    : false;

  const renderCell = (row: OrderDto, colId: string) => {
    switch (colId) {
      case 'code':
        return (
          <button
            type="button"
            className={erp.codeLink}
            onClick={() => navigateToRow(row.id)}
            data-testid={`${TEST_ID}-row-${row.id}-code`}
          >
            <code>{row.code}</code>
          </button>
        );
      case 'orderDate':
        return formatDateLocal(row.orderDate);
      case 'customerName':
        return row.customerName;
      case 'totalAmount':
        return <span className={erp.colRight}>{formatVnd(row.totalAmount)}</span>;
      case 'status':
        return <VoucherStatusBadge status={row.status} />;
      default:
        return null;
    }
  };

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canApprove: canConfirmActive,
      approveDisabled: !canConfirmActive || confirming,
      onApprove: handleConfirmActive,
      canViewLedger: false,
      canPrint: false,
      canView: canViewActive,
      onView: () => activeRow && navigateToRow(activeRow.id),
      canEdit: canEditActive,
      onEdit: () => activeRow && navigateToRow(activeRow.id, true),
      canCreate,
      onCreate: () => navigate('/bh/dh/them'),
      onEditConfig: () => setShowConfigModal(true),
    }),
    [
      canConfirmActive,
      confirming,
      canViewActive,
      canEditActive,
      canCreate,
      activeRow,
      refresh,
      navigate,
      navigateToRow,
    ],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            placeholder="Tìm số ĐH, khách hàng, diễn giải..."
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label="Trạng thái"
            value={status}
            onChange={e => {
              setStatus(e.target.value);
              resetPage();
            }}
            options={STATUS_OPTIONS}
            fullWidth
            data-testid={`${TEST_ID}-status`}
          />
        ),
      },
    ],
    [
      searchDraft,
      fromDate,
      toDate,
      datePreset,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      setStatus,
      handleSearch,
    ],
  );

  const batchBar =
    selection.selectedCount > 0 ? (
      <div className={erp.batchBar} data-testid={`${TEST_ID}-batch-bar`}>
        <span>Đã chọn {selection.selectedCount}</span>
        <button
          type="button"
          className={erp.batchBarLink}
          data-testid={`${TEST_ID}-batch-clear`}
          onClick={selection.clearSelection}
        >
          Bỏ chọn tất cả
        </button>
      </div>
    ) : null;

  const listBody =
    !showTableLoading && items.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <p>Không có đơn hàng</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper} data-testid={`${TEST_ID}-table-wrapper`}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th className={erp.colCheck}>
                <span className="sr-only">Chọn</span>
              </th>
              {visibleColumns.map(col => (
                <th key={col.id}>{col.label}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {items.map(row => {
              const isActive = selection.isRowActive(row);
              const isChecked = selection.isRowChecked(row);
              return (
                <tr
                  key={row.id}
                  className={[
                    isChecked ? erp.catalogRowChecked : '',
                    isActive ? erp.catalogRowActive : '',
                  ]
                    .filter(Boolean)
                    .join(' ')}
                  onClick={() => selection.selectActiveRow(row)}
                  onContextMenu={e => {
                    e.preventDefault();
                    handleRowOpenActionMenu({ row, x: e.clientX, y: e.clientY });
                  }}
                  data-testid={`${TEST_ID}-row-${row.id}`}
                >
                  <td className={erp.colCheck}>
                    {row.status === 'Draft' ? (
                      <input
                        type="checkbox"
                        checked={isChecked}
                        onChange={() => selection.toggleRow(row, !isChecked)}
                        onClick={e => e.stopPropagation()}
                        data-testid={`${TEST_ID}-row-${row.id}-check`}
                      />
                    ) : null}
                  </td>
                  {visibleColumns.map(col => (
                    <td key={col.id}>{renderCell(row, col.id)}</td>
                  ))}
                </tr>
              );
            })}
          </tbody>
        </table>
        <p className={erp.rowMenuHint} data-testid={`${TEST_ID}-row-menu-hint`}>
          {rowMenuHintMessage}
        </p>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: 'Đơn hàng bán',
          titleIconClass: 'fas fa-shopping-cart',
          pageId: PAGE_ID,
        }}
        voucherToolbar={voucherToolbar}
        beforeToolbar={batchBar}
        listTitle="Danh sách đơn hàng"
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={Math.min(pageSize, 8)}
        footer={
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => {
              setPage(p);
              selection.clearSelection();
            }}
            onPageSizeChange={setPageSize}
          />
        }
        modals={
          <>
            <LinListTableConfigModal
              isOpen={showConfigModal}
              onClose={() => setShowConfigModal(false)}
              testIdPrefix={TEST_ID}
              config={tableConfig}
              onSave={handleSaveTableConfig}
            />
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView
              showEdit={rowMenuShowEdit}
              showViewLedger={false}
              showPrint={false}
            />
          </>
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default DonHangList;
